import re
from datetime import datetime

# Get review ratings
review_data = locals()['var_functions.query_db:18']
ratings_dict = {}
for item in review_data:
    ratings_dict[item['gmap_id']] = float(item['avg_rating'])

print('Loaded ratings for', len(ratings_dict), 'businesses')

# Get business data file path
business_file_key = 'var_functions.query_db:24'
business_file_path = locals()[business_file_key]

print('Business data file path:', business_file_path)

with open(business_file_path, 'r') as f:
    all_businesses = json.load(f)

print('Total businesses with hours:', len(all_businesses))

# Filter businesses that are open after 6 PM on weekdays
weekdays = ['Monday', 'Tuesday', 'Wednesday', 'Thursday', 'Friday']
open_after_6pm = []

def parse_time(time_str):
    """Parse time like '9:30PM' or '10PM'"""
    try:
        time_str = time_str.upper().strip()
        if ':' in time_str:
            return datetime.strptime(time_str, '%I:%M%p')
        else:
            return datetime.strptime(time_str, '%I%p')
    except:
        return None

for business in all_businesses:
    try:
        gmap_id = business['gmap_id']
        if gmap_id not in ratings_dict:
            continue

        hours_str = business.get('hours', '')
        if not hours_str or hours_str == 'None':
            continue

        # Parse the hours string (it's a string representation of a list)
        hours_clean = hours_str.replace("'", '"')
        hours_list = json.loads(hours_clean)

        is_open_late = False
        for day_entry in hours_list:
            if isinstance(day_entry, list) and len(day_entry) >= 2:
                day_name = day_entry[0]
                time_range = day_entry[1]

                if day_name in weekdays and time_range and time_range != 'Closed':
