                    if '\u2013' in time_range:
                        parts = time_range.split('\u2013')
                    elif '\u2014' in time_range:
                        parts = time_range.split('\u2014')
                    elif '-' in time_range:
                        parts = time_range.split('-')
                    else:
                        continue

                    if len(parts) >= 2:
                        closing_str = parts[1].strip()
                        if closing_str == 'Open 24 hours':
                            is_open_late = True
                            break
                        elif closing_str == 'Closed':
                            continue

                        closing_time = parse_time(closing_str)
                        if closing_time and (closing_time.hour > 18 or (closing_time.hour == 18 and closing_time.minute > 0)):
                            is_open_late = True
                            break

        if is_open_late:
            open_after_6pm.append({
                'gmap_id': gmap_id,
                'name': business.get('name', 'Unknown'),
                'hours': hours_str,
                'avg_rating': ratings_dict[gmap_id]
            })

    except Exception as e:
        continue

print('Businesses open after 6pm on weekdays:', len(open_after_6pm))

# Get top 5 by rating
top_5 = sorted(open_after_6pm, key=lambda x: x['avg_rating'], reverse=True)[:5]

result = []
for biz in top_5:
    result.append({
        'name': biz['name'],
        'hours': biz['hours'],
